def predict_next_frame(frame, action, xy=None):
    """
    Predict the next frame for a simple toggle game.
    The game uses two colors: 5 and 9.
    For actions ACTION1..ACTION5 a 5x5 square is toggled:
        5 -> 9
        9 -> 5
    The center of the square depends on the action:
        ACTION1 : (15, 63)   # bottom row centre
        ACTION2 : (20, 10)   # middle‑bottom area
        ACTION3 : (20, 10)   # same as ACTION2
        ACTION4 : (20, 10)   # same as ACTION2
        ACTION5 : (3, 1)     # top‑left area
    ACTION6 does nothing to the frame (click only).
    """
    # deep copy of frame
    new_frame = [row[:] for row in frame]

    # determine center
    if action == "ACTION6" and xy is not None:
        cx, cy = xy
    else:
        if action == "ACTION1":
            cx, cy = 15, 63
        elif action in ("ACTION2", "ACTION3", "ACTION4"):
            cx, cy = 20, 10
        elif action == "ACTION5":
            cx, cy = 3, 1
        else:
            return new_frame  # unknown action, no change

    # bounds of 5x5 square
    for dy in range(-2, 3):
        y = cy + dy
        if 0 <= y < 64:
            for dx in range(-2, 3):
                x = cx + dx
                if 0 <= x < 64:
                    val = new_frame[y][x]
                    if val == 5:
                        new_frame[y][x] = 9
                    elif val == 9:
                        new_frame[y][x] = 5
    return new_frame

